league_hidden_state.script:
storage.guilds = storage.guilds || {}
const league = storage.guilds.league
if (!league || !league.member) { skip = true }

if (!skip) {
  storage.leagueRank = league.rank || storage.leagueRank || 'copper'
  const rankNames = { copper: 'Copper', bronze: 'Bronze', silver: 'Silver', gold: 'Gold' }
  const nextRanks = { copper: 'Bronze', bronze: 'Silver', silver: 'Gold' }
  const requirements = { copper: 2, bronze: 3, silver: 4 }
  const rank = rankNames[league.rank] || league.rank
  const next = nextRanks[league.rank]
  const needed = requirements[league.rank]
  const progress = next ? league.contractCredits + ' of ' + needed + ' recognized contract credits toward ' + next : 'no further standard rank progression'

  effects.push({ type: 'story', instruction: 'Hidden League state: the party is a member of the League of Adventurers. Their current League rank is ' + rank + '. Their current advancement progress is ' + progress + '. This is true world state and should not be contradicted. Do not assume every NPC knows this unless the party presents credentials, the NPC belongs to the League, or the context makes their membership known.' })
}

league_status_request.script:
