league_promotion_request.script:
storage.guilds = storage.guilds || {}
const league = storage.guilds.league
if (!league || !league.member) { skip = true }

if (!skip) {
  const rankNames = { copper: 'Copper', bronze: 'Bronze', silver: 'Silver', gold: 'Gold' }
  const nextRanks = { copper: 'Bronze', bronze: 'Silver', silver: 'Gold' }
  const requirements = { copper: 2, bronze: 3, silver: 4 }
  const rank = rankNames[league.rank] || league.rank
  const next = nextRanks[league.rank]
  const needed = requirements[league.rank]

  if (!next || !needed) {
    storage.leaguePromotionPending = false
    effects.push({ type: 'story', instruction: 'IF the player requests League promotion, the party is already at the highest standard League rank currently tracked. A League official should not invent a higher ordinary promotion unless the story has established a special honor. Disregard this instruction if the player is not requesting League promotion.' })
  } else if ((league.contractCredits || 0) >= needed) {
    storage.leaguePromotionPending = true
    effects.push({ type: 'story', instruction: 'IF the player requests League promotion, the party meets the League requirements for promotion from ' + rank + ' to ' + next + '. If they are speaking with a League registrar, ranking officer, or authorized chapterhouse representative, that official may formally promote them in this scene. Disregard this instruction if the player is not requesting League promotion.' })
  } else {
    storage.leaguePromotionPending = false
    effects.push({ type: 'story', instruction: 'IF the player requests League promotion, the party does not yet meet the League requirements for promotion from ' + rank + ' to ' + next + '. They have ' + league.contractCredits + ' of ' + needed + ' recognized contract credits. A League official may acknowledge their progress, but should not grant the higher rank yet. Disregard this instruction if the player is not requesting League promotion.' })
  }
}

