  storage.towerShadowRank = order.rank || storage.towerShadowRank || 'initiate'
  const rankNames = { initiate: 'Initiate', shadow: 'Shadow', adept: 'Adept', master: 'Master' }
  const nextRanks = { initiate: 'Shadow', shadow: 'Adept', adept: 'Master' }
  const requirements = { initiate: 2, shadow: 3, adept: 4 }
  const rank = rankNames[order.rank] || order.rank
  const next = nextRanks[order.rank]
  const needed = requirements[order.rank]
  const progress = next ? order.caseCredits + ' of ' + needed + ' recognized Shadow case credits toward ' + next : 'no further standard rank progression'

  effects.push({ type: 'story', instruction: 'Hidden Tower of Shadow state: the party is sworn to the Tower of Shadow. Their current rank is ' + rank + '. Their current advancement progress is ' + progress + '. This is true world state and should not be contradicted. The Tower is secretive; do not assume ordinary NPCs know this unless the party reveals credentials, the NPC belongs to the Tower, or the context makes it known.' })
}

