tower_shadow_promotion_request.script:
storage.guilds = storage.guilds || {}
const order = storage.guilds.towerShadow
if (!order || !order.member) { skip = true }

if (!skip) {
  const rankNames = { initiate: 'Initiate', shadow: 'Shadow', adept: 'Adept', master: 'Master' }
  const nextRanks = { initiate: 'Shadow', shadow: 'Adept', adept: 'Master' }
  const requirements = { initiate: 2, shadow: 3, adept: 4 }
  const rank = rankNames[order.rank] || order.rank
  const next = nextRanks[order.rank]
  const needed = requirements[order.rank]

  if (!next || !needed) {
    storage.towerShadowPromotionPending = false
    effects.push({ type: 'story', instruction: 'IF the player requests Tower promotion, the party is already at Master rank, the highest standard rank currently tracked. Do not invent a higher ordinary promotion unless the story has established a special title or office. Disregard this instruction if the player is not requesting Tower promotion.' })
  } else if ((order.caseCredits || 0) >= needed) {
    storage.towerShadowPromotionPending = true
    effects.push({ type: 'story', instruction: 'IF the player requests Tower promotion, the party meets the case requirements for promotion from ' + rank + ' to ' + next + '. If they are speaking with Jett, a mentor, a Master of Shadow, or another authorized Tower representative, that authority may formally advance them. If the promotion is from Initiate to Shadow, the rite should involve the Pit of Shadow and the Rite of Bonding; becoming Shadow means becoming Shade-Bonded. Disregard this instruction if the player is not requesting Tower promotion.' })
  } else {
    storage.towerShadowPromotionPending = false
    effects.push({ type: 'story', instruction: 'IF the player requests Tower promotion, the party does not yet meet the Tower requirements for promotion from ' + rank + ' to ' + next + '. They have ' + order.caseCredits + ' of ' + needed + ' recognized Shadow case credits. A Tower authority may acknowledge their progress, but should not grant the higher rank yet. Disregard this instruction if the player is not requesting Tower promotion.' })
  }
}

